import { quote, claim, runScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("Quote - Base premiums", () => {
    it.todo("should return 5G for an empty item list (only processing fee)");
    it.todo("should return 115G for a single sword (100G base + 10G first insurance + 5G fee)");
