    it.todo("should return 93G for a single staff (80G base + 8G first insurance + 5G fee)");
    it.todo("should return 49G for a single potion (40G base + 4G first insurance + 5G fee)");
  });

  describe("Quote - Component pricing", () => {
    it.todo("should return 2 runes as 50G base premium (2 x 25G)");
    it.todo("should return 3 runes as 60G base premium (block of 3 alike applies)");
    it.todo("should return 4 runes as 100G base premium (no block — block requires exactly 3)");
    it.todo("should return 7 runes as 175G base premium (7 x 25G, no block)");
    it.todo("should return 2 runes + 1 moonstone as 75G base premium (no block: different types)");
    it.todo("should return 3 runes + 3 moonstones as 120G base premium (two separate blocks: 60G + 60G)");
  });

  describe("Quote - Item-level modifiers", () => {
    it.todo("should add 50% curse surcharge to a cursed sword (100G + 50G = 150G before policy modifiers)");
    it.todo("should add 30% high-enchantment surcharge for sword with enchantment 5 (100G + 30G = 130G before policy modifiers)");
    it.todo("should not add high-enchantment surcharge for sword with enchantment 4 (100G before policy modifiers)");
