    it.todo("should apply cursed surcharge only to the cursed item: cursed sword + plain amulet = 210G before policy modifiers and fee");
  });

  describe("Quote - Policy-level modifiers", () => {
    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
    it.todo("should apply loyalty discount for customer with exactly 2 years");
    it.todo("should not apply loyalty discount for customer with 1 year");
    it.todo("should always apply 10% first insurance surcharge on every quote");
    it.todo("should apply 15% follow-up contract discount on second quote in scenario");
