    it.todo("should return payout 400G for regular sword (steel, ench 3) with 500G damage (full reimbursement minus 100G deductible)");
    it.todo("should return payout 100G for rune with 200G damage (full reimbursement minus 100G deductible; no special clauses)");
  });

  describe("Claim - Deductible per damage event", () => {
    it.todo("should apply 100G deductible per damaged item: sword 500G + amulet 300G = payout 600G (400 + 200)");
  });

  describe("Claim - Enchantment and dragon material clauses", () => {
    it.todo("should return payout 400G for dragon-material sword ench 9, damage 1000G (both clauses: 50% wins, 500 - 100 deductible)");
    it.todo("should return payout 700G for dragon-material sword ench 5, damage 800G (only dragon clause: 800 - 100 deductible)");
    it.todo("should return payout 400G for steel sword ench 9, damage 1000G (only high-ench clause: 50% = 500, minus 100 deductible)");
